import styled from '@emotion/styled'
import tw from 'twin.macro'
import * as React from 'react'
import { graphql, HeadFC, Link, useStaticQuery } from 'gatsby'
import { GatsbyImage, getImage } from 'gatsby-plugin-image'
import Layout from '../components/layout'
import { ReactComponent as PatternsOverviewImage } from '../images/patterns-overview_1.5x.svg'
import Seo from '../components/seo'
import Updates from '../components/updates'

const menus = [
  {
    label: 'Design Patterns',
    href: '#design-patterns',
    style: {
      background: 'linear-gradient(99deg, #0788ff, #9900ff)',
    },
  },
  {
    label: 'Rendering Patterns',
    href: '#rendering-patterns',
    style: {
      background: 'linear-gradient(45deg, #ff6800, #e233ff)',
    },
  },
  {
    label: 'Performance Patterns',
    href: '#performance-patterns',
    style: { background: 'linear-gradient(45deg, #73eca1, #54b6d4)' },
  },
]

const IndexPage: React.FC = () => {
  const {
    allMarkdownRemark: { group },
  } = useStaticQuery(graphql`
    query {
      allMarkdownRemark(sort: { fields: frontmatter___displayOrder }) {
        group(field: frontmatter___category) {
          nodes {
            id
            fields {
              slug
            }
            frontmatter {
              title
              tags
              subtitle
              inProgress
              featuredImage {
                childImageSharp {
                  gatsbyImageData(
                    width: 672
                    placeholder: BLURRED
                    formats: [AUTO, WEBP, AVIF]
                  )
                }
              }
            }
          }
          fieldValue
        }
      }
    }
  `)

  const designPatterns = group.find(
    ({ fieldValue }: any) => fieldValue === 'design patterns'
  ).nodes
  const renderingPatterns = group.find(
    ({ fieldValue }: any) => fieldValue === 'rendering patterns'
  ).nodes
  const performancePatterns = group.find(
    ({ fieldValue }: any) => fieldValue === 'performance patterns'
  ).nodes
  const caseStudies = group.find(
    ({ fieldValue }: any) => fieldValue === 'case studies'
  ).nodes

  const onClickMenu = React.useCallback(
    (e: React.SyntheticEvent<HTMLAnchorElement>) => {
      e.preventDefault()
      const href = e.currentTarget.getAttribute('href')

      if (!href) {
        return
      }

      const element = document.querySelector(href)

      if (!element) {
        return
      }

      window.scrollTo({
        top: element.getBoundingClientRect().top - 64,
        behavior: 'smooth',
      })
    },
    []
  )

  return (
    <Layout>
      <div tw="pt-16">
        <div tw="flex flex-wrap items-center justify-between overflow-hidden">
          <div tw="text-center md:text-left w-full md: max-w-xl">
            <h1 tw="mb-4 text-5xl font-bold">Patterns</h1>
            <p tw="text-xl text-gray-600 break-words">
              디자인 및 성능 패턴에 대한 최신 정보들을 제공합니다.
            </p>
          </div>
          <div tw="h-0 w-0 md:w-auto md:h-auto">
            <PatternsOverviewImage
              width={300}
              height={300}
              tw="invisible md:visible"
            />
          </div>
        </div>

        <Updates />

        {/* MENUS */}
        <div tw="mb-8">
          <div tw="grid gap-12 items-start md:col-gap-6 md:grid-cols-3 md:row-gap-8">
            {menus.map(({ label, href, style }) => (
              <article key={href} tw="flex flex-col h-36">
                <a
                  href={href}
                  onClick={onClickMenu}
                  tw="flex w-full h-full drop-shadow-lg font-bold items-center justify-center rounded text-white text-xl hover:no-underline"
                  style={style}
                >
                  {label}
                </a>
              </article>
            ))}
          </div>
        </div>

        {/* DESIGN PATTERNS */}
        <Articles
          title="Design Patterns"
          anchorId="design-patterns"
          articles={designPatterns}
        />

        {/* RENDERING PATTERNS */}
        <Articles
          title="Rendering Patterns"
          anchorId="rendering-patterns"
          articles={renderingPatterns}
        />

        {/* PERFORMANCE PATTERNS */}
        <Articles
          title="Performance Patterns"
          anchorId="performance-patterns"
          articles={performancePatterns}
        />

        {/* CASE STUDIES */}
        <Articles
          title="Case Studies"
          anchorId="case-studies"
          articles={caseStudies}
        />
      </div>
    </Layout>
  )
}

/* eslint-disable react/prop-types */
export const Head: HeadFC = ({ location }) => (
  <Seo pathname={location.pathname} title="Home" />
)
/* eslint-enable react/prop-types */

export default IndexPage

interface ArticleProps {
  title: string
  anchorId: string
  articles: {
    id: string
    fields: { slug: string }
    frontmatter: {
      title: string
      tags: null | string[]
      subtitle: string
      inProgress: null | true
      featuredImage: any
    }
  }[]
}

const Articles: React.FC<ArticleProps> = ({ title, anchorId, articles }) => (
  <>
    <h2 tw="font-bold text-3xl mt-16 mb-6" id={anchorId}>
      {title}
    </h2>
    <div tw="grid gap-12 items-start md:grid-cols-3 md:col-gap-6 md:row-gap-8">
      {articles.map(({ id, fields, frontmatter }) => (
        <StyledArticle key={id}>
          <Link to={fields.slug} tw="hover:no-underline">
            <div tw="rounded overflow-hidden mb-2 relative">
              {frontmatter.inProgress && (
                <>
                  <div tw="w-full h-full flex absolute inset-0 opacity-80 bg-black z-10" />
                  <div tw="w-full h-full flex absolute inset-0 font-bold justify-center items-center text-3xl md:text-xl text-white z-20">
                    번역 준비중
                  </div>
                </>
              )}
              <GatsbyImage
                image={getImage(frontmatter.featuredImage)!}
                alt={frontmatter.title}
                tw="overflow-hidden aspect-video"
              />
            </div>
            {frontmatter.tags && (
              <div tw="mb-3 flex gap-2 mx-1">
                {frontmatter.tags.map(tag => (
                  <span
                    key={tag}
                    tw="px-4 py-2 rounded-full shadow-sm shadow-gray-300 text-gray-800 visited:text-gray-800 bg-white text-center hover:bg-gray-100 transition-colors duration-200"
                  >
                    {tag}
                  </span>
                ))}
              </div>
            )}
            <h3 tw="tracking-tight leading-snug font-bold text-xl text-black visited:text-black mx-1">
              {frontmatter.title}
            </h3>
            <h3 tw="tracking-tight leading-snug text-lg text-gray-600 visited:text-gray-600 mx-1">
              {frontmatter.subtitle}
            </h3>
          </Link>
        </StyledArticle>
      ))}
    </div>
  </>
)

const StyledArticle = styled.article`
  ${tw`flex flex-col h-full relative`}

  .gatsby-image-wrapper [data-main-image] {
    ${tw`block scale-105 transition-transform duration-200 ease-in-out`}
  }

  &:hover {
    .gatsby-image-wrapper [data-main-image] {
      ${tw`scale-105 -translate-y-1`}
    }
  }
`
