import 'twin.macro'
import { useStaticQuery, graphql, Link } from 'gatsby'
import * as React from 'react'
import styled from '@emotion/styled'

interface UpdatesProps {}

const Updates: React.FC<UpdatesProps> = () => {
  const {
    allMarkdownRemark: { group },
  } = useStaticQuery<{
    allMarkdownRemark: {
      group: {
        fieldValue: string
        nodes: {
          id: string
          fields: { slug: string }
          frontmatter: { addedAt: string; title: string }
        }[]
      }[]
    }
  }>(
    graphql`
      query {
        allMarkdownRemark(
          sort: { fields: frontmatter___displayOrder, order: ASC }
        ) {
          group(field: frontmatter___addedAt) {
            fieldValue
            nodes {
              id
              frontmatter {
                title
              }
              fields {
                slug
              }
            }
          }
        }
      }
    `
  )

  const chunks = [...group].sort(
    (a, b) => Number(new Date(b.fieldValue)) - Number(new Date(a.fieldValue))
  )
  const [{ nodes: latestAddedList }] = chunks

  return (
    <details tw="my-16 relative">
      <StyledSummary tw="h-8 flex justify-start items-center px-2 py-1 bg-purple-50 rounded transition-colors duration-200 ease-in-out hover:bg-purple-100 cursor-pointer shadow">
        <span tw="flex h-3 w-3 absolute top-[-0.25rem] right-[-0.25rem]">
          <span tw="animate-ping absolute inline-flex h-full w-full rounded-full bg-purple-400 opacity-75" />
          <span tw="relative inline-flex rounded-full h-3 w-3 bg-purple-500" />
        </span>
        <span tw="text-sm font-bold text-red-500 mr-2 shrink-0 tracking-tighter">
          📣 UPDATE
        </span>
        <span tw="truncate">
          {latestAddedList.length > 1 ? (
            <>
              <Link to={latestAddedList[0].fields.slug}>
                {latestAddedList[0].frontmatter.title}
              </Link>
              외 {latestAddedList.length - 1}개의 새로운 번역 글의
              추가되었습니다
            </>
          ) : (
            <>
              <Link to={latestAddedList[0].fields.slug}>
                {latestAddedList[0].frontmatter.title}
              </Link>{' '}
              새로운 번역 글이 추가되었습니다
            </>
          )}
        </span>
      </StyledSummary>
      <ul tw="absolute z-10 top-8 left-0 bg-gray-50 rounded-b w-full shadow">
        {chunks.map(chunk => {
          const [, m, d] =
            chunk.fieldValue.match(/^\d{4}-(\d{2})-(\d{2})/) || []

          return (
            <li
              key={chunk.fieldValue}
              tw="flex justify-start items-center text-sm"
            >
              <span tw="mr-4 shrink-0">
                {m}/{d}
              </span>
              <span tw="p-2">
                {chunk.nodes.map((node, index) => (
                  <span key={node.id} className="new-links">
                    <Link to={node.fields.slug}>{node.frontmatter.title}</Link>
                    {chunk.nodes.length - 1 > index && ', '}
                  </span>
                ))}
                <span tw="ml-2">새로운 번역 글이 추가되었습니다</span>
              </span>
            </li>
          )
        })}
      </ul>
    </details>
  )
}

export default Updates

const StyledSummary = styled.summary`
  list-style: none;

  &::-webkit-details-marker {
    display: none;
  }
`
